//! Reference model for bounded IR (mirrors distributed-inference lift semantics).

use crate::ir::{LiftOutcomeV0, SieveFsmIrV0};
use crate::lift_reference::{
    apply_dark_deceptacon_resolution_lift, attention_closure_state, ResolutionLiftAction,
};

pub fn lift_outcome(ir: &SieveFsmIrV0) -> LiftOutcomeV0 {
    let heads = ir.heads as usize;
    let coupling = ir.coupling as usize;
    let observer = ir.observer_resolution as usize;
    let threshold = ir.residue_threshold as usize;

    let state = attention_closure_state(heads, coupling, observer);
    let decision = apply_dark_deceptacon_resolution_lift(state, threshold);
    let lift = matches!(decision.action, ResolutionLiftAction::LiftResolution);
    LiftOutcomeV0 {
        lift,
        after_observer_resolution: decision.after_observer_resolution.min(u16::MAX as usize) as u16,
    }
}
